from langchain_core.tools import BaseToolkit, BaseTool, tool
from pydantic import BaseModel, Field
from typing import Any

class WeatherClient:
    """Hypothetical weather API client."""
    def __init__(self, api_key: str):
        self.api_key = api_key

    def current(self, city: str) -> dict:
        return {"city": city, "temp_c": 22, "condition": "sunny"}

    def forecast(self, city: str, days: int) -> list[dict]:
        return [{"day": i + 1, "temp_c": 20 + i} for i in range(days)]

class WeatherToolkit(BaseToolkit):
    client: Any = Field(exclude=True)   # not serialised

    def get_tools(self) -> list[BaseTool]:
        client = self.client

        @tool
        def get_current_weather(city: str) -> dict:
            """Get current weather for a city."""
            return client.current(city)

        @tool
        def get_weather_forecast(city: str, days: int = 3) -> list[dict]:
            """Get a multi-day weather forecast for a city."""
            return client.forecast(city, days)

        return [get_current_weather, get_weather_forecast]

# Usage
weather_client  = WeatherClient(api_key="key-xyz")
weather_toolkit = WeatherToolkit(client=weather_client)
weather_tools   = weather_toolkit.get_tools()
llm_weather     = llm.bind_tools(weather_tools)

@tool(handle_tool_error=True)
def risky_division(numerator: float, denominator: float) -> float:
    """Divide numerator by denominator."""
    return numerator / denominator
# A ZeroDivisionError is caught and sent back as a ToolMessage error string
# instead of crashing the agent.

# Custom error message as a callable
def format_tool_error(e: Exception) -> str:
    return f"Tool failed: {type(e).__name__}: {e}. Please try different inputs."

@tool(handle_tool_error=format_tool_error)
def query_db(sql: str) -> list:
    """Execute a SQL SELECT query and return rows."""
    import sqlite3
    conn = sqlite3.connect("data.db")
    return conn.execute(sql).fetchall()

# Return a ToolMessage with is_error=True from within the tool
from langchain_core.messages import ToolMessage

@tool
def safe_parse_json(text: str) -> dict | str:
    """Parse a JSON string and return a dict."""
    try:
        import json
        return json.loads(text)
    except json.JSONDecodeError as e:
        return f"JSON parse error: {e} — input was: {text[:100]}"
# The agent sees the error string and can ask the LLM to fix the JSON

import pytest
from langchain_core.tools import tool

@tool
def celsius_to_fahrenheit(celsius: float) -> float:
    """Convert a temperature from Celsius to Fahrenheit."""
    return celsius * 9 / 5 + 32

def test_celsius_to_fahrenheit_freezing():
    result = celsius_to_fahrenheit.invoke({"celsius": 0.0})
    assert result == 32.0

def test_celsius_to_fahrenheit_boiling():
    result = celsius_to_fahrenheit.invoke({"celsius": 100.0})
    assert result == 212.0

def test_celsius_to_fahrenheit_body_temp():
    result = celsius_to_fahrenheit.invoke({"celsius": 37.0})
    assert abs(result - 98.6) < 0.01

# Test error handling
@tool(handle_tool_error=True)
def divide(a: float, b: float) -> float:
    """Divide a by b."""
    return a / b

def test_divide_zero_returns_string_not_raise():
    result = divide.invoke({"a": 10.0, "b": 0.0})
    assert isinstance(result, str)
    assert "ZeroDivisionError" in result or "error" in result.lower()
